// IF YOU HAVE NOT ALREADY READ PATIENT_CARE_RULES.md, STOP AND READ IT BEFORE EDITING THIS FILE.
(function(){
'use strict';
const BUNDLE_ROUTE='#/patient/bundle/';
const DRAFT_KEY='pc_patient_bundle_draft_v1';
const QUEUE_KEY='pc_patient_bundle_setup_queue_v2';
const LANG_KEY='pc_patient_language';
const MAX_TOOLS=6;
const TOOLS={
  v:{en:'Vitamin D',ar:'فيتامين د',short:'D',builder:'#/physician/vitamin-d'},
  o:{en:'Iron tablets',ar:'حبوب الحديد',short:'Fe',builder:'#/physician/iron-oral'},
  i:{en:'IV iron',ar:'الحديد الوريدي',short:'IV',builder:'#/physician/iron-iv'},
  b:{en:'BP readings',ar:'قراءات الضغط',short:'BP',builder:'#/physician/blood-pressure'}
};
let activeIndex=0,observer=null,enhancing=false,selection=new Set();
function esc(v){return String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function encode(v){return btoa(unescape(encodeURIComponent(JSON.stringify(v)))).replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'')}
function decode(v){try{const s=String(v).replace(/-/g,'+').replace(/_/g,'/');return JSON.parse(decodeURIComponent(escape(atob(s+'==='.slice((s.length+3)%4)))))}catch(e){return null}}
function date(v){return new Date(String(v)+'T12:00:00')}
function iso(v){return v.toISOString().slice(0,10)}
function addDays(v,n){const d=date(v);d.setDate(d.getDate()+n);return iso(d)}
function ar(){return localStorage.getItem(LANG_KEY)==='ar'}
function toast(v){if(typeof window.showToast==='function')window.showToast(v)}
function loadDraft(){try{const v=JSON.parse(sessionStorage.getItem(DRAFT_KEY));return v&&v.v===1&&Array.isArray(v.t)?v:{v:1,t:[]}}catch(e){return {v:1,t:[]}}}
function saveDraft(v){sessionStorage.setItem(DRAFT_KEY,JSON.stringify({v:1,t:(v.t||[]).slice(0,MAX_TOOLS)}))}
function clearDraft(){sessionStorage.removeItem(DRAFT_KEY);sessionStorage.removeItem(QUEUE_KEY)}
function loadQueue(){try{const q=JSON.parse(sessionStorage.getItem(QUEUE_KEY));return Array.isArray(q)?q.filter(k=>TOOLS[k]):[]}catch(e){return []}}
function saveQueue(q){sessionStorage.setItem(QUEUE_KEY,JSON.stringify(q.filter(k=>TOOLS[k])))}
function itemKey(x){return JSON.stringify(x)}
function addItem(item){const d=loadDraft();if(!item||!TOOLS[item.k])return {error:'This patient tool could not be added.'};if(d.t.some(x=>itemKey(x)===itemKey(item)))return {duplicate:true,draft:d};if(d.t.length>=MAX_TOOLS)return {error:`A patient bundle can contain up to ${MAX_TOOLS} tools.`};d.t.push(item);saveDraft(d);return {draft:d}}
function removeItem(i){const d=loadDraft();d.t.splice(i,1);saveDraft(d)}
function compact(kind,data){
  if(kind==='v')return {k:'v',p:data};
  if(kind==='o')return {k:'o',p:{v:1,kind:'oral',f:data.f,u:data.u,ed:data.ed,g:data.g,w:data.w,s:data.s,r:data.r,c:data.c||''}};
  if(kind==='i')return {k:'i',p:{v:1,kind:'iv',p:data.p,t:data.t,g:data.g,r:data.r,c:data.c||'',preset:data.preset||'',i:(data.i||[]).map(x=>({date:x.date,mg:x.mg,ml:x.ml}))}};
  if(kind==='b')return {k:'b',p:data};
  return null;
}
function expand(item){
  if(item.k==='b')return '#/patient/blood-pressure/'+encode(item.p||{});
  const d={...(item.p||{})};if(item.k==='o'&&!Array.isArray(d.d)){const gap=Number(d.g)||1,weeks=Number(d.w)||0,count=Math.floor((weeks*7-1)/gap)+1;d.d=Array.from({length:Math.max(0,count)},(_,i)=>addDays(d.s,i*gap))}
  const code=encode(d);return item.k==='v'?'#/patient/vitamin-d/'+code:item.k==='o'?'#/patient/iron-oral/'+code:item.k==='i'?'#/patient/iron-iv/'+code:'';
}
function parseLink(value){try{const route=new URL(value,location.href).hash;for(const [prefix,kind] of [['#/patient/blood-pressure/','b'],['#/patient/vitamin-d/','v'],['#/patient/iron-oral/','o'],['#/patient/iron-iv/','i']]){if(route.startsWith(prefix)){const d=decode(route.slice(prefix.length));return d?compact(kind,d):null}}}catch(e){}return null}
function bundleCode(d){return encode({v:1,t:d.t})}
function bundleUrl(d){return location.origin+location.pathname+location.search+BUNDLE_ROUTE+bundleCode(d)}
function names(items){const total={},seen={};items.forEach(x=>total[x.k]=(total[x.k]||0)+1);return items.map(x=>{seen[x.k]=(seen[x.k]||0)+1;const n=ar()?TOOLS[x.k].ar:TOOLS[x.k].en;return n+(total[x.k]>1?` ${seen[x.k]}`:'')})}
function closeChooser(){document.getElementById('patient-bundle-chooser')?.remove();document.body.classList.remove('patient-bundle-modal-open');selection.clear()}
function chooserHtml(){const draft=loadDraft(),remaining=MAX_TOOLS-draft.t.length;return `<div class="patient-bundle-backdrop" data-close-bundle-chooser></div><section class="patient-bundle-dialog" role="dialog" aria-modal="true" aria-labelledby="bundle-title"><button type="button" class="patient-bundle-close" data-close-bundle-chooser aria-label="Close">×</button><p class="eyebrow">PATIENT BUNDLE</p><h2 id="bundle-title">Choose patient tools</h2><p>Select all the tools you want. Each selected tool will open for setup before the combined link is created.</p><div class="patient-bundle-tool-grid">${Object.entries(TOOLS).map(([k,x])=>`<button type="button" data-bundle-toggle-tool="${k}" aria-pressed="${selection.has(k)}" class="${selection.has(k)?'selected':''}"><span>${x.short}</span><strong>${x.en}</strong><small>${selection.has(k)?'Selected':'Tap to select'}</small></button>`).join('')}</div><p class="patient-bundle-size-note"><strong>${selection.size}</strong> selected · ${remaining} space${remaining===1?'':'s'} available</p><div class="patient-bundle-actions"><button type="button" class="btn ghost" data-close-bundle-chooser>Cancel</button><button type="button" class="btn dr" data-bundle-continue ${selection.size?'':'disabled'}>Continue</button></div></section>`}
function openChooser(){closeChooser();selection=new Set();const m=document.createElement('div');m.id='patient-bundle-chooser';m.className='patient-bundle-modal';m.innerHTML=chooserHtml();document.body.appendChild(m);document.body.classList.add('patient-bundle-modal-open');m.querySelector('[data-bundle-toggle-tool]')?.focus()}
function refreshChooser(){const m=document.getElementById('patient-bundle-chooser');if(m)m.innerHTML=chooserHtml()}
function toggleTool(k){const limit=MAX_TOOLS-loadDraft().t.length;if(selection.has(k))selection.delete(k);else if(selection.size<limit)selection.add(k);else{toast(`A patient bundle can contain up to ${MAX_TOOLS} tools.`);return}refreshChooser()}
function nextSetup(){const q=loadQueue();if(!q.length){location.hash='#/physician';return}location.hash=TOOLS[q[0]].builder}
function continueSelection(){const q=[...selection];if(!q.length)return;saveQueue(q);closeChooser();nextSetup()}
function qr(el,url){try{const q=qrcode(0,'L');q.addData(url);q.make();el.innerHTML=q.createSvgTag({cellSize:4,margin:4,scalable:true})}catch(e){el.textContent='Use the patient link.'}}
function renderBuilder(){if(location.hash!=='#/physician')return;const screen=document.querySelector('.physician-screen'),grid=screen?.querySelector('.physician-tool-grid');if(!screen||!grid)return;const d=loadDraft(),sig=JSON.stringify(d),old=document.getElementById('patient-bundle-builder');if(old?.dataset.signature===sig)return;const s=old||document.createElement('section');s.id='patient-bundle-builder';s.className='patient-bundle-builder';s.dataset.signature=sig;if(!d.t.length)s.innerHTML=`<div><p class="eyebrow">ONE LINK FOR THE PATIENT</p><h2>Patient tool bundle</h2><p>Choose several tools, configure each one, then create one patient link.</p></div><button type="button" class="btn dr" data-bundle-start>Start a patient bundle</button>`;else{const n=names(d.t),url=bundleUrl(d);s.innerHTML=`<div class="patient-bundle-title"><div><p class="eyebrow">PATIENT BUNDLE</p><h2>${d.t.length} tool${d.t.length===1?'':'s'} in one link</h2><p>Add more tools now or share the combined patient link.</p></div><button type="button" class="btn ghost danger" data-bundle-clear>Clear bundle</button></div><div class="patient-bundle-items">${d.t.map((x,i)=>`<article class="patient-bundle-item"><span>${TOOLS[x.k].short}</span><strong>${esc(n[i])}</strong><button type="button" data-bundle-remove="${i}">×</button></article>`).join('')}</div><div class="patient-bundle-handoff"><div id="patient-bundle-qr" class="vitd-qr"></div><div><label class="vitd-link-label">Combined patient link<input id="patient-bundle-link" readonly value="${esc(url)}"></label><div class="patient-bundle-actions"><button type="button" class="btn dr" data-bundle-open>Open combined patient page</button><button type="button" class="btn ghost" data-bundle-copy>Copy combined link</button><button type="button" class="btn ghost" data-bundle-add>Add more tools</button></div></div></div>`;requestAnimationFrame(()=>{const el=document.getElementById('patient-bundle-qr');if(el)qr(el,url)})}if(!old)screen.insertBefore(s,grid)}
function enhanceExports(){for(const box of [document.getElementById('vitd-export'),document.getElementById('oral-export'),document.getElementById('ivp-export'),document.getElementById('bp-config-export')].filter(Boolean)){if(box.hidden)continue;const actions=box.querySelector('.vitd-export-actions');if(!actions||actions.querySelector('[data-bundle-add-current]'))continue;const b=document.createElement('button');b.type='button';b.className='btn ghost';b.dataset.bundleAddCurrent='1';b.textContent=loadDraft().t.length?'Add to patient bundle':'Add this and more tools';actions.appendChild(b)}}
function enhance(){if(enhancing)return;enhancing=true;try{renderBuilder();enhanceExports()}finally{enhancing=false}}
function removeNav(){document.getElementById('patient-bundle-nav')?.remove();document.body.classList.remove('patient-bundle-active')}
function validBundle(b){return b&&b.v===1&&Array.isArray(b.t)&&b.t.length&&b.t.length<=MAX_TOOLS&&b.t.every(x=>x&&TOOLS[x.k]&&expand(x))}
function renderChild(route,bundleHash){history.replaceState(null,'',location.pathname+location.search+route);try{if(route.startsWith('#/patient/blood-pressure/')&&typeof window.renderConfiguredBpPatient==='function')window.renderConfiguredBpPatient(route.slice('#/patient/blood-pressure/'.length));else if(route.startsWith('#/patient/iron-')&&typeof window.handleIronRoute==='function')window.handleIronRoute();else previousRoute()}finally{history.replaceState(null,'',location.pathname+location.search+bundleHash)}}
function renderBundle(code,index){const b=decode(code);if(!validBundle(b))return false;activeIndex=Math.max(0,Math.min(Number.isInteger(index)?index:activeIndex,b.t.length-1));renderChild(expand(b.t[activeIndex]),BUNDLE_ROUTE+code);removeNav();document.body.classList.add('patient-bundle-active');const nav=document.createElement('nav'),n=names(b.t);nav.id='patient-bundle-nav';nav.className='patient-bundle-nav';nav.innerHTML=b.t.map((x,i)=>`<button type="button" data-bundle-tool-index="${i}" class="${i===activeIndex?'active':''}" aria-current="${i===activeIndex?'page':'false'}"><span>${TOOLS[x.k].short}</span><strong>${esc(n[i])}</strong></button>`).join('');document.body.appendChild(nav);return true}
function routeIsBundle(){return location.hash.startsWith(BUNDLE_ROUTE)}
const previousRoute=window.route;window.route=function(){if(routeIsBundle())return renderBundle(location.hash.slice(BUNDLE_ROUTE.length),activeIndex);removeNav();const r=previousRoute.apply(this,arguments);requestAnimationFrame(enhance);return r};
async function copyLink(){const i=document.getElementById('patient-bundle-link');if(!i)return;try{await navigator.clipboard.writeText(i.value);toast('Combined patient link copied')}catch(e){i.select();document.execCommand?.('copy');toast('Combined patient link copied')}}
function addCurrent(button){const box=button.closest('.vitd-export'),value=box?.querySelector('#vitd-patient-link,#oral-link,#ivp-link,#bp-patient-link')?.value||'',item=parseLink(value);if(!item){alert('Generate the patient plan first.');return}const result=addItem(item);if(result.error){alert(result.error);return}const q=loadQueue(),idx=q.indexOf(item.k);if(idx>=0)q.splice(idx,1);saveQueue(q);toast(result.duplicate?'This plan is already in the bundle.':'Plan added to the patient bundle.');if(q.length)nextSetup();else location.hash='#/physician'}
document.addEventListener('click',async e=>{if(e.target.closest('[data-bundle-start],[data-bundle-add]')){openChooser();return}if(e.target.closest('[data-close-bundle-chooser]')){closeChooser();return}const toggle=e.target.closest('[data-bundle-toggle-tool]');if(toggle){toggleTool(toggle.dataset.bundleToggleTool);return}if(e.target.closest('[data-bundle-continue]')){continueSelection();return}const rem=e.target.closest('[data-bundle-remove]');if(rem){removeItem(Number(rem.dataset.bundleRemove));renderBuilder();return}if(e.target.closest('[data-bundle-clear]')){if(confirm('Clear this patient bundle?')){clearDraft();renderBuilder()}return}if(e.target.closest('[data-bundle-open]')){const d=loadDraft();if(d.t.length)location.hash=BUNDLE_ROUTE+bundleCode(d);return}if(e.target.closest('[data-bundle-copy]')){await copyLink();return}const current=e.target.closest('[data-bundle-add-current]');if(current){addCurrent(current);return}const tool=e.target.closest('[data-bundle-tool-index]');if(tool&&routeIsBundle()){renderBundle(location.hash.slice(BUNDLE_ROUTE.length),Number(tool.dataset.bundleToolIndex));window.scrollTo({top:0,behavior:'smooth'});return}});
document.addEventListener('keydown',e=>{if(e.key==='Escape'&&document.getElementById('patient-bundle-chooser'))closeChooser()});
window.addEventListener('hashchange',()=>setTimeout(()=>{if(routeIsBundle())renderBundle(location.hash.slice(BUNDLE_ROUTE.length),activeIndex);else enhance()},0));
function start(){const root=document.getElementById('app');if(root&&!observer){observer=new MutationObserver(()=>requestAnimationFrame(()=>{if(routeIsBundle()){const b=decode(location.hash.slice(BUNDLE_ROUTE.length));if(validBundle(b)&&!document.getElementById('patient-bundle-nav'))renderBundle(location.hash.slice(BUNDLE_ROUTE.length),activeIndex)}else enhance()}));observer.observe(root,{childList:true,subtree:true})}enhance();if(routeIsBundle())renderBundle(location.hash.slice(BUNDLE_ROUTE.length),activeIndex)}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',start,{once:true});else start();
})();